   313	            string connectionString,
   314	            DatabaseModelFactoryOptions databaseOptions,
   315	            ModelReverseEngineerOptions modelOptions,
   316	            ModelCodeGenerationOptions codeOptions,
   317	            bool removeNullableBoolDefaults,
