   326	            if (removeNullableBoolDefaults)
   327	            {
   328	                foreach (var column in databaseModel.Tables
   329	                    .SelectMany(table => table.Columns
   330	                        .Where(column => (
   331	                            (column.StoreType == "bit" || column.StoreType == "boolean" || column.StoreType == "bit(1)")
   332	                            && !column.IsNullable
   333	                            && !string.IsNullOrEmpty(column.DefaultValueSql))
   334	                            ||
