   337	                            (column.StoreType == "NUMBER(1)"
   338	                                && !column.IsNullable
   339	                                && !string.IsNullOrEmpty(column.DefaultValueSql)
   340	                                && (column.DefaultValueSql?.Trim() == "1" || column.DefaultValueSql?.Trim() == "0")))))
   341	                {
   342	                    column.DefaultValueSql = null;
