   241	        private static string RemoveMatchingBraces(string s)
   242	        {
   243	            var stack = new Stack<char>();
   244	            var count = 0;
   245	            foreach (var ch in s)
   246	            {
   247	                switch (ch)
   248	                {
   249	                    case '(':
   250	                        count += 1;
   251	                        stack.Push(ch);
   252	                        break;
   253	                    case ')':
   254	                        if (count == 0)
   255	                        {
   256	                            stack.Push(ch);
   257	                        }
   258	                        else
   259	                        {
   260	                            char popped;
   261	                            do
   262	                            {
   263	                                popped = stack.Pop();
   264	                            }
   265	                            while (popped != '(');
   266	                            count -= 1;
   267	                        }
   268	
   269	                        break;
   270	                    default:
   271	                        stack.Push(ch);
   272	                        break;
   273	                }
   274	            }
   275	
   276	            return string.Join(string.Empty, stack.Reverse());
   277	        }
