   170	        private static NpgsqlDbType GetNpgsqlDbType(string storeType)
   171	        {
   172	            if (string.IsNullOrEmpty(storeType))
   173	            {
   174	                throw new ArgumentException("storeType not specified");
   175	            }
   176	
   177	            var cleanedTypeName = RemoveMatchingBraces(storeType);
   178	
   179	            if (cleanedTypeName == null)
   180	            {
   181	                throw new ArgumentOutOfRangeException(nameof(storeType), $"Unable to remove braces: {storeType}");
   182	            }
   183	
   184	#pragma warning disable CA1308 // Normalize strings to uppercase
   185	            if (SqlTypeAliases.TryGetValue(cleanedTypeName.ToLowerInvariant(), out var alias))
   186	            {
   187	                cleanedTypeName = alias;
   188	            }
   189	#pragma warning restore CA1308 // Normalize strings to uppercase
   190	
   191	            if (!Enum.TryParse(cleanedTypeName, true, out NpgsqlDbType result))
   192	            {
   193	                throw new ArgumentOutOfRangeException(nameof(storeType), $"cleanedTypeName: {cleanedTypeName}");
   194	            }
   195	
   196	            return result;
   197	        }
