   199	        private static string RemoveMatchingBraces(string s)
   200	        {
   201	            var stack = new Stack<char>();
   202	            var count = 0;
   203	            foreach (var ch in s)
   204	            {
   205	                switch (ch)
   206	                {
   207	                    case '(':
   208	                        count += 1;
   209	                        stack.Push(ch);
   210	                        break;
   211	                    case ')':
   212	                        if (count == 0)
   213	                        {
   214	                            stack.Push(ch);
   215	                        }
   216	                        else
   217	                        {
   218	                            char popped;
   219	                            do
   220	                            {
   221	                                popped = stack.Pop();
   222	                            }
   223	                            while (popped != '(');
   224	                            count -= 1;
   225	                        }
   226	
   227	                        break;
   228	                    default:
   229	                        stack.Push(ch);
   230	                        break;
   231	                }
   232	            }
   233	
   234	            return string.Join(string.Empty, stack.Reverse());
   235	        }
   236	    }
   237	}

